  "raw_nodes": [
    {
      "title": "PHYSICS Subject Code – 042 Class XI-XII (2025-26)",
      "level": "header",
      "parent": null,
      "source_text": "PHYSICS Subject Code – 042 Class XI-XII (2025-26) Senior Secondary stage of school education is a stage of transition from general education to discipline-based focus on curriculum. The present updated syllabus keeps in view the rigor and depth of disciplinary approach as well as the comprehension level of learners."
    },
    {
      "title": "Salient features",
      "level": "heading",
      "parent": null,
      "source_text": "Emphasis on basic conceptual understanding; Use of SI units; Logical sequencing; Reducing curriculum load; Promotion of process-skills"
    },
    {
      "title": "COURSE STRUCTURE Class XI - 2026-27 (Theory)",
      "level": "header",
      "parent": null,
      "source_text": "Time: 3 hrs. Max Marks: 70"
    },
    {
      "title": "Unit–I Physical World and Measurement",
      "level": "unit_header",
      "parent": null,
      "source_text": "23 marks; Chapter–1: Units and Measurements"
    },
    {
      "title": "Chapter 1 Content Class XI",
      "level": "chapter_content",
      "parent": "Unit I",
      "source_text": "Need for measurement, units of measurement, systems of units, SI units, fundamental and derived units, significant figures, uncertainty in result, dimensions, dimensional analysis"
    },
    {
      "title": "Chapter 2 Content Class XI",
      "level": "chapter_content",
      "parent": "Unit II",
      "source_text": "Frame of reference, motion in straight line, differentiation and integration for describing motion, uniform/non-uniform motion, average speed/velocity/instantaneous velocity, uniformly accelerated motion, graphs"
    },
    {
      "title": "Chapter 3 Content Class XI",
      "level": "chapter_content",
      "parent": "Unit II",
      "source_text": "Scalar and vector quantities, vectors operations, resolution of vectors, scalar/vector product, projectile motion, uniform circular motion"
    },
    {
      "title": "Chapter 4 Content Class XI",
      "level": "chapter_content",
      "parent": "Unit III",
      "source_text": "Force, Inertia, Newton's laws, momentum, impulse, conservation of linear momentum, equilibrium, friction (static/kinetic/rolling), circular motion dynamics"
    },
    {
      "title": "Chapter 5 Content Class XI",
      "level": "chapter_content",
      "parent": "Unit IV",
      "source_text": "Work done by constant and variable force, kinetic energy, work-energy theorem, power, potential energy, conservative/non-conservative forces, collisions"
    },
    {
      "title": "Chapter 6 Content Class XI",
      "level": "chapter_content",
      "parent": "Unit V",
      "source_text": "Centre of mass, momentum conservation, torque, angular momentum, equilibrium of rigid bodies, rotational motion equations, moment of inertia"
    },
    {
      "title": "Chapter 7 Content Class XI",
      "level": "chapter_content",
      "parent": "Unit VI",
      "source_text": "Kepler's laws, universal law of gravitation, acceleration due to gravity variation, gravitational potential energy/potential, escape speed, orbital velocity"
    },
    {
      "title": "Chapter 8 Content Class XI",
      "level": "chapter_content",
      "parent": "Unit VII",
      "source_text": "Elasticity, stress-strain relationship, Hooke's law, Young’s modulus, bulk/shear/Poisson's ratio, elastic energy"
    },
    {
      "title": "Chapter 9 Content Class XI",
      "level": "chapter_content",
      "parent": "Unit VII",
      "source_text": "Fluid pressure, Pascal's law, viscosity, Stokes' law, Bernoulli's theorem, surface tension"
    },
    {
      "title": "Chapter 10 Content Class XI",
      "level": "chapter_content",
      "parent": "Unit VII",
      "source_text": "Heat, temperature, thermal expansion, specific heat capacity, latent heat, heat transfer (conduction/convection/radiation), Blackbody radiation"
    },
    {
      "title": "Chapter 11 Content Class XI",
      "level": "chapter_content",
      "parent": "Unit VIII",
      "source_text": "Thermal equilibrium, zeroth law, heat/work/internal energy, first and second laws of thermodynamics, processes (isothermal/adiabatic/cyclic)"
    },
    {
      "title": "Chapter 12 Content Class XI",
      "level": "chapter_content",
      "parent": "Unit IX",
      "source_text": "Equation of state, kinetic theory assumptions, pressure concept, rms speed, degrees of freedom, mean free path"
    },
    {
      "title": "Chapter 13 Content Class XI",
      "level": "chapter_content",
      "parent": "Unit X",
      "source_text": "Periodic motion, S.H.M., simple pendulum derivation, energy in S.H.M."
    },
    {
      "title": "Chapter 14 Content Class XI",
      "level": "chapter_content",
      "parent": "Unit X",
      "source_text": "Wave motion types, speed of wave, superposition principle, standing waves, beats"
    },
    {
      "title": "PRACTICALS CLASS XI EVALUATION SCHEME",
      "level": "header",
      "parent": null,
      "source_text": "Time 3 hours Max. Marks: 30; Two experiments one from each section (7+7); Practical record (5); One activity (3); Investigatory Project (3); Viva (5)"
    },
    {
      "title": "SECTION–A Experiments Class XI",
      "level": "section_header",
      "parent": null,
      "source_text": "1. Vernier Callipers; 2. Screw gauge; 3. Irregular lamina volume; 4. Spherometer; 5. Beam balance; 6. Parallelogram law of vectors"
    },
    {
      "title": "SECTION–A Activities Class XI",
      "level": "section_header",
      "parent": null,
      "source_text": "1. Paper scale; 2. Mass by moments; 3. Graph plotting with error bars; 4. Limiting friction rolling; 5. Projectile range variation; 6. Conservation of energy inclined plane"
    },
    {
      "title": "SECTION–B Experiments Class XI",
      "level": "section_header",
      "parent": null,
      "source_text": "1. Young's modulus; 2. Force constant spring; 3. Boyle's law (P-V); 4. Surface tension capillary rise; 5. Viscosity terminal velocity"
    },
    {
      "title": "SECTION–B Activities Class XI",
      "level": "section_header",
      "parent": null,
      "source_text": "1. Cooling curve molten wax; 2. Bi-metallic strip heating; 3. Liquid level change on heating"
    },
    {
      "title": "PHYSICS (THEORY) CLASS XII COURSE STRUCTURE",
      "level": "header",
      "parent": null,
      "source_text": "Time: 3 hrs. Max Marks: 70; Unit–I Electrostatics (16 marks); Unit-II Current Electricity; Unit-III Magnetic Effects of Current and Magnetism (17 marks)"
    },
    {
      "title": "Chapter 1 Content Class XII",
      "level": "chapter_content",
      "parent": "Unit I",
      "source_text": "Electric charges, Coulomb's law, superposition principle, electric field lines, dipole torque, Gauss's theorem applications"
    },
    {
      "title": "Chapter 2 Content Class XII",
      "level": "chapter_content",
      "parent": "Unit I",
      "source_text": "Electric potential, equipotential surfaces, electrical potential energy, conductors/insulators/dielectrics, capacitors and capacitance"
    },
    {
      "title": "Chapter 3 Content Class XII",
      "level": "chapter_content",
      "parent": "Unit II",
      "source_text": "Electric current, drift velocity, Ohm's law, V-I characteristics, resistivity/conductivity, internal resistance of cell, Kirchhoff's rules"
    },
    {
      "title": "Chapter 4 Content Class XII",
      "level": "chapter_content",
      "parent": "Unit III",
      "source_text": "Magnetic field concept, Biot-Savart law, Ampere's law, force on moving charge/conductor, torque on current loop"
    },
    {
      "title": "Chapter 5 Content Class XII",
      "level": "chapter_content",
      "parent": "Unit III",
      "source_text": "Bar magnet as solenoid, magnetic dipole moment, magnetic properties of materials (para/dia/ferro), effect of temperature"
    },
    {
      "title": "Chapter 6 Content Class XII",
      "level": "chapter_content",
      "parent": "Unit IV",
      "source_text": "Electromagnetic induction, Faraday's laws, Lenz's Law, Self and mutual induction"
    },
    {
      "title": "Chapter 7 Content Class XII",
      "level": "chapter_content",
      "parent": "Unit IV",
      "source_text": "Alternating currents, peak/RMS value, reactance/impedance, LCR series circuit resonance, power in AC circuits"
    },
    {
      "title": "Chapter 8 Content Class XII",
      "level": "chapter_content",
      "parent": "Unit V",
      "source_text": "Displacement current, electromagnetic waves characteristics, transverse nature, EM spectrum uses"
    },
    {
      "title": "Chapter 9 Content Class XII",
      "level": "chapter_content",
      "parent": "Unit VI",
      "source_text": "Reflection of light, spherical mirrors, mirror formula, refraction, total internal reflection, lenses, optical instruments"
    },
    {
      "title": "Chapter 10 Content Class XII",
      "level": "chapter_content",
      "parent": "Unit VI",
      "source_text": "Wave optics, Huygen's principle, interference (Young's double slit), diffraction due to single slit"
    },
    {
      "title": "Chapter 11 Content Class XII",
      "level": "chapter_content",
      "parent": "Unit VII",
      "source_text": "Dual nature of radiation, Photoelectric effect, Einstein's equation, Matter waves, de-Broglie relation"
    },
    {
      "title": "Chapter 12 Content Class XII",
      "level": "chapter_content",
      "parent": "Unit VIII",
      "source_text": "Alpha-particle scattering, Rutherford's model, Bohr model of hydrogen atom, line spectra (qualitative)"
    },
    {
      "title": "Chapter 13 Content Class XII",
      "level": "chapter_content",
      "parent": "Unit VIII",
      "source_text": "Nuclei composition/size, nuclear force, mass-energy relation, binding energy per nucleon, fission/fusion"
    },
    {
      "title": "Chapter 14 Content Class XII",
      "level": "chapter_content",
      "parent": "Unit IX",
      "source_text": "Energy bands in conductors/semiconductors/insulators, p-n junction diode I-V characteristics, rectifier applications"
    },
    {
      "title": "PRACTICALS CLASS XII EVALUATION SCHEME",
      "level": "header",
      "parent": null,
      "source_text": "Time 3 hours Max. Marks: 30; Two experiments one from each section (7+7); Practical record (5); One activity (3); Investigatory Project (3); Viva (5)"
    },
    {
      "title": "SECTION–A Experiments Class XII",
      "level": "section_header",
      "parent": null,
      "source_text": "1. Resistivity of wires; 2. Metre bridge resistance; 3. Laws of combination series/parallel; 4. Galvanometer figure of merit"
    },
    {
      "title": "SECTION–A Activities Class XII",
      "level": "section_header",
      "parent": null,
      "source_text": "1. Inductor resistance/impedance; 2. Multimeter usage (R/V/I); 3. Household circuit assembly"
    },
    {
      "title": "SECTION–B Experiments Class XII",
      "level": "section_header",
      "parent": null,
      "source_text": "1. Concave mirror focal length; 2. Convex mirror focal length; 3. Convex lens focal length graphs"
    },
    {
      "title": "SECTION–B Activities Class XII",
      "level": "section_header",
      "parent": null,
      "source_text": "1. Identify diode/LED/resistor/capacitor; 2. Multimeter unidirectional flow check"
    },
    {
      "title": "Suggested Investigatory Projects Class XII",
      "level": "section_header",
      "parent": null,
      "source_text": "1. Internal resistance/EMF factors; 2. LDR current variation with light intensity/distance"
    },
    {
      "title": "QUESTION PAPER DESIGN CLASS XI/XII",
      "level": "header",
      "parent": null,
      "source_text": "Theory Max Marks: 70 Duration: 3 hrs; Remembering/Understanding (27 marks); Applying (22 marks); Analysing/Evaluating/Creating (21 marks)"
    },
    {
      "title": "Practical Examination for Visually Impaired Students",
      "level": "header",
      "parent": null,
      "source_text": "Time 2 hours Max. Marks: 30; Identification/Familiarity (5); Written test (10); Practical Record (5); Viva (10)"
    }
  ],
